// Constants for SHA-1 operations
constexpr int CPUID_EBX_SHA_BIT = 29;                               // CPUID bit for SHA-NI support detection
constexpr size_t BCRYPT_MAX_CHUNK_BYTES = 1ULL * 1024 * 1024 * 1024; // 1GB max for BCryptHashData (ULONG limit)

// Helper: Build wide path from base + subpath
static void make_path(wchar_t* dest, size_t dest_size, const wchar_t* base, const wchar_t* sub) {
    wcscpy_s(dest, dest_size, base);
    size_t len = wcslen(dest);
    if (len > 0 && dest[len - 1] != L'\\' && dest[len - 1] != L'/') {
        wcscat_s(dest, dest_size, L"\\");
    }
    wcscat_s(dest, dest_size, sub);
}

// Helper: Strip trailing whitespace/newlines from string
static void strip_trailing(char* str) {
    size_t len = strlen(str);
    while (len > 0 && (str[len - 1] == '\n' || str[len - 1] == '\r' || str[len - 1] == ' ')) {
        str[--len] = '\0';
    }
}

// Look up a full ref name (e.g. "refs/heads/main") in packed-refs via mmap.
// Avoids fixed-buffer truncation used by older readers.
// out_sha must hold at least Git::SHA1_HEX_SIZE + 1 bytes.
static bool packed_refs_lookup_sha(const wchar_t* git_dir, const char* full_ref, char* out_sha) {
    if (!git_dir || !full_ref || !out_sha) return false;
    out_sha[0] = '\0';

    wchar_t packed_refs_path[Git::MAX_PATH_LEN];
    make_path(packed_refs_path, Git::MAX_PATH_LEN, git_dir, L"packed-refs");

    MemoryMap* map = mmap_open(packed_refs_path);
    if (!map || !map->data || map->size == 0) {
        mmap_close(map);
        return false;
    }

    const char* data = static_cast<const char*>(map->data);
    size_t size = map->size;
    size_t full_ref_len = strlen(full_ref);
    bool found = false;

    size_t i = 0;
    while (i < size) {
        size_t line_start = i;
        while (i < size && data[i] != '\n' && data[i] != '\r') i++;
        size_t line_len = i - line_start;
        while (i < size && (data[i] == '\n' || data[i] == '\r')) i++;

        if (line_len == 0) continue;
        if (data[line_start] == '#' || data[line_start] == '^') continue;
        if (line_len > 41 && data[line_start + 40] == ' ') {
            size_t ref_len = line_len - 41;
            if (ref_len == full_ref_len &&
                memcmp(data + line_start + 41, full_ref, full_ref_len) == 0) {
                memcpy(out_sha, data + line_start, Git::SHA1_HEX_SIZE);
                out_sha[Git::SHA1_HEX_SIZE] = '\0';
                found = true;
                break;
            }
        }
    }

    mmap_close(map);
    return found;
}

// Resolve refs/<...> under .git to a 40-char SHA. Loose ref files take
// precedence over packed-refs. Follows symbolic refs with a depth limit.
static bool resolve_ref_sha(const wchar_t* git_dir, const char* ref_path_utf8,
                            char* out_sha, int symref_depth = 0) {
    if (!git_dir || !ref_path_utf8 || !out_sha) return false;
    out_sha[0] = '\0';
    if (symref_depth > 5) return false;

    wchar_t ref_path_wide[Git::MAX_PATH_LEN];
    utf8_to_wide_n(ref_path_utf8, ref_path_wide, Git::MAX_PATH_LEN);
    for (wchar_t* p = ref_path_wide; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    wchar_t full_path[Git::MAX_PATH_LEN];
    make_path(full_path, Git::MAX_PATH_LEN, git_dir, ref_path_wide);

    char content[256];
    size_t n = read_file(full_path, content, sizeof(content));
    if (n > 0) {
        strip_trailing(content);
        if (strncmp(content, "ref: ", 5) == 0) {
            return resolve_ref_sha(git_dir, content + 5, out_sha, symref_depth + 1);
        }
        if (strlen(content) >= Git::SHA1_HEX_SIZE) {
            strncpy_s(out_sha, Git::SHA1_HEX_SIZE + 1, content, Git::SHA1_HEX_SIZE);
            out_sha[Git::SHA1_HEX_SIZE] = '\0';
            return true;
        }
    }

    return packed_refs_lookup_sha(git_dir, ref_path_utf8, out_sha);
}

// Case-insensitive equality for a path segment of known length.
static bool path_segment_ieq(const char* seg, size_t len, const char* lit) {
    size_t lit_len = strlen(lit);
    if (len != lit_len) return false;
    for (size_t i = 0; i < len; i++) {
        char a = seg[i];
        char b = lit[i];
        if (a >= 'A' && a <= 'Z') a = static_cast<char>(a - 'A' + 'a');
        if (b >= 'A' && b <= 'Z') b = static_cast<char>(b - 'A' + 'a');
        if (a != b) return false;
    }
    return true;
}

// Windows reserves device names as path basenames (case-insensitive), with or
// without an extension: CON, PRN, AUX, NUL, COM1–COM9, LPT1–LPT9.
static bool is_windows_reserved_basename(const char* segment, size_t len) {
    // Strip a trailing extension for the reserved-name check (CON.txt → CON).
    size_t base_len = len;
    for (size_t i = 0; i < len; i++) {
        if (segment[i] == '.') {
            base_len = i;
            break;
        }
    }
    if (base_len == 0) return false;

    if (path_segment_ieq(segment, base_len, "con") ||
        path_segment_ieq(segment, base_len, "prn") ||
        path_segment_ieq(segment, base_len, "aux") ||
        path_segment_ieq(segment, base_len, "nul")) {
        return true;
    }

    // COM1–COM9 / LPT1–LPT9
    if (base_len == 4) {
        char c0 = segment[0];
        char c1 = segment[1];
        char c2 = segment[2];
        char c3 = segment[3];
        if (c0 >= 'A' && c0 <= 'Z') c0 = static_cast<char>(c0 - 'A' + 'a');
        if (c1 >= 'A' && c1 <= 'Z') c1 = static_cast<char>(c1 - 'A' + 'a');
        if (c2 >= 'A' && c2 <= 'Z') c2 = static_cast<char>(c2 - 'A' + 'a');
        if ((c0 == 'c' && c1 == 'o' && c2 == 'm') ||
            (c0 == 'l' && c1 == 'p' && c2 == 't')) {
            if (c3 >= '1' && c3 <= '9') return true;
        }
    }
    return false;
}

// Git tree/index paths are repository-relative POSIX paths. Reject paths that
// cannot be safely mapped to a Windows worktree path, or that would write into
// repository metadata / reserved device names.
static bool git_is_safe_relative_path(const char* path) {
    if (!path || path[0] == '\0') return false;
    if (path[0] == '/' || path[0] == '\\') return false;
    if (path[1] == ':') return false;  // Drive-qualified path.

    size_t total_len = strlen(path);
    if (path[total_len - 1] == '/' || path[total_len - 1] == '\\') return false;
    // Windows strips trailing dots/spaces from final path components; reject so
    // two different git paths cannot collapse onto one on-disk name.
    if (path[total_len - 1] == '.' || path[total_len - 1] == ' ') return false;

    const char* segment = path;
    while (*segment) {
        const char* end = segment;
        while (*end && *end != '/') {
            if (*end == '\\' || *end == ':') return false;
            end++;
        }

        size_t len = end - segment;
        if (len == 0) return false;
        if (len == 1 && segment[0] == '.') return false;
        if (len == 2 && segment[0] == '.' && segment[1] == '.') return false;

        // Hostile trees that place a `.git` component would write into the
        // repository metadata directory under a normal worktree root.
        if (path_segment_ieq(segment, len, ".git")) return false;

        // Segment-level trailing dots/spaces (not only path-final)
        if (segment[len - 1] == '.' || segment[len - 1] == ' ') return false;

        if (is_windows_reserved_basename(segment, len)) return false;

        segment = (*end == '/') ? end + 1 : end;
    }

    return true;
}

static bool git_make_worktree_path(GitRepository* repo, const char* rel_path,
                                   wchar_t* out_path, size_t out_size) {
    if (!repo || !rel_path || !out_path || out_size == 0) return false;
    if (!git_is_safe_relative_path(rel_path)) return false;

    wchar_t repo_wide[Git::MAX_PATH_LEN];
    wchar_t rel_wide[Git::MAX_PATH_LEN];
    if (!utf8_to_wide_n(repo->path, repo_wide, Git::MAX_PATH_LEN)) return false;
    if (!utf8_to_wide_n(rel_path, rel_wide, Git::MAX_PATH_LEN)) return false;

    for (wchar_t* p = rel_wide; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    wchar_t combined[Git::MAX_PATH_LEN];
    make_path(combined, Git::MAX_PATH_LEN, repo_wide, rel_wide);

    wchar_t root_full[Git::MAX_PATH_LEN];
    wchar_t target_full[Git::MAX_PATH_LEN];
    DWORD root_len = GetFullPathNameW(repo_wide, Git::MAX_PATH_LEN, root_full, nullptr);
    DWORD target_len = GetFullPathNameW(combined, Git::MAX_PATH_LEN, target_full, nullptr);
    if (root_len == 0 || root_len >= Git::MAX_PATH_LEN ||
        target_len == 0 || target_len >= Git::MAX_PATH_LEN) {
        return false;
    }

    size_t root_count = wcslen(root_full);
    while (root_count > 0 && (root_full[root_count - 1] == L'\\' || root_full[root_count - 1] == L'/')) {
        root_full[--root_count] = L'\0';
    }

    if (_wcsnicmp(target_full, root_full, root_count) != 0) return false;
    wchar_t next = target_full[root_count];
    if (next != L'\0' && next != L'\\' && next != L'/') return false;

    wcscpy_s(out_path, out_size, target_full);
    return true;
}

static bool git_ensure_worktree_parent_dirs(const wchar_t* file_path, const wchar_t* repo_root) {
    if (!file_path || !repo_root) return false;

    wchar_t parent_path[Git::MAX_PATH_LEN];
    wcscpy_s(parent_path, file_path);

    wchar_t* last_slash = wcsrchr(parent_path, L'\\');
    if (!last_slash) return true;
    *last_slash = L'\0';

    DWORD attrs = GetFileAttributesW(parent_path);
    if (attrs != INVALID_FILE_ATTRIBUTES && (attrs & FILE_ATTRIBUTE_DIRECTORY)) {
        return true;
    }

    wchar_t root_full[Git::MAX_PATH_LEN];
    DWORD root_len_dw = GetFullPathNameW(repo_root, Git::MAX_PATH_LEN, root_full, nullptr);
    if (root_len_dw == 0 || root_len_dw >= Git::MAX_PATH_LEN) return false;

    size_t root_len = wcslen(root_full);
    while (root_len > 0 && (root_full[root_len - 1] == L'\\' || root_full[root_len - 1] == L'/')) {
        root_full[--root_len] = L'\0';
    }

    if (_wcsnicmp(parent_path, root_full, root_len) != 0) return false;
    if (parent_path[root_len] != L'\0' && parent_path[root_len] != L'\\' && parent_path[root_len] != L'/') {
        return false;
    }

    wchar_t create_path[Git::MAX_PATH_LEN];
    wcscpy_s(create_path, root_full);

    const wchar_t* relative = parent_path + root_len;
    if (*relative == L'\\' || *relative == L'/') relative++;

    while (*relative) {
        const wchar_t* next_slash = wcschr(relative, L'\\');
        const wchar_t* next_fwd = wcschr(relative, L'/');
        if (!next_slash || (next_fwd && next_fwd < next_slash)) next_slash = next_fwd;

        size_t segment_len = next_slash ? static_cast<size_t>(next_slash - relative) : wcslen(relative);
        if (segment_len == 0) return false;

        wcscat_s(create_path, Git::MAX_PATH_LEN, L"\\");
        wcsncat_s(create_path, Git::MAX_PATH_LEN, relative, segment_len);

        attrs = GetFileAttributesW(create_path);
        if (attrs == INVALID_FILE_ATTRIBUTES) {
            if (!CreateDirectoryW(create_path, nullptr)) {
                DWORD err = GetLastError();
                if (err != ERROR_ALREADY_EXISTS) return false;
            }
        } else if (!(attrs & FILE_ATTRIBUTE_DIRECTORY)) {
            return false;
        }

        if (!next_slash) break;
        relative = next_slash + 1;
    }

    return true;
}

